mapper.select:
select a.id, 'AUC-' || lpad(a.id::text, 3, '0') as auction_code, w.title as work_title, sm.nickname as artist_name, wm.nickname as winner_name, a.starting_price, a.final_price, a.bid_count, to_char(a.closing_at, 'MM.DD HH24:MI') as closing_at, case a.status when 'SOLD' then '낙찰' when 'CLOSED' then '유찰' end as status from tbl_auction a join tbl_work w on a.work_id = w.id join tbl_member sm on a.seller_id = sm.id left join tbl_member wm on a.winner_id = wm.id where a.status in ('CLOSED', 'SOLD')
and ( w.title ilike '%' || #{keyword} || '%' or sm.nickname ilike '%' || #{keyword} || '%' )
and a.status = #{status}
order by a.id desc limit #{size} offset #{offset}

select count(*) from tbl_auction a join tbl_work w on a.work_id = w.id join tbl_member sm on a.seller_id = sm.id left join tbl_member wm on a.winner_id = wm.id where a.status in ('CLOSED', 'SOLD')
and ( w.title ilike '%' || #{keyword} || '%' or sm.nickname ilike '%' || #{keyword} || '%' )
and a.status = #{status}
